#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef class_T
#define class_T float
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 16
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef ENABLE_DP
#define USE_DOUBLE
#endif

#ifdef ENABLE_HP
#define USE_HALF
#endif

#ifdef BLOCK_STRIDED
#define STRIDE_MODE blockdim
#else
#define STRIDE_MODE 1
#endif

typedef class_T element_t;

#ifdef USE_HALF
typedef short half2[2];
#endif

__attribute__((noinline))
element_t bench_block(element_t* data, element_t f, size_t static_chunk_size) {
  element_t sum = 0;

#ifdef BASELINE_IMPL
  for (size_t i = 0; i < static_chunk_size; i++) {
    element_t t = data[i];
    for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
      t = t * t + f;
    }
    sum += t;
  }
#else
  element_t f_arr[8];
  for (int k = 0; k < 8; k++) {
    f_arr[k] = f;
  }

  for (size_t i = 0; i < static_chunk_size; i++) {
    element_t t[8];
    for (int k = 0; k < 8; k++) {
      t[k] = data[i];
    }

    size_t main_iters = COMPUTE_ITERATIONS / 8;
    for (size_t j = 0; j < main_iters; j++) {
      t[0] = t[0] * t[0] + f_arr[0];
      t[1] = t[1] * t[1] + f_arr[1];
      t[2] = t[2] * t[2] + f_arr[2];
      t[3] = t[3] * t[3] + f_arr[3];
      t[4] = t[4] * t[4] + f_arr[4];
      t[5] = t[5] * t[5] + f_arr[5];
      t[6] = t[6] * t[6] + f_arr[6];
      t[7] = t[7] * t[7] + f_arr[7];
    }

    size_t remainder = COMPUTE_ITERATIONS % 8;
    if (remainder > 0) {
      t[0] = t[0] * t[0] + f_arr[0];
    }
    if (remainder > 1) {
      t[1] = t[1] * t[1] + f_arr[1];
    }
    if (remainder > 2) {
      t[2] = t[2] * t[2] + f_arr[2];
    }
    if (remainder > 3) {
      t[3] = t[3] * t[3] + f_arr[3];
    }
    if (remainder > 4) {
      t[4] = t[4] * t[4] + f_arr[4];
    }
    if (remainder > 5) {
      t[5] = t[5] * t[5] + f_arr[5];
    }
    if (remainder > 6) {
      t[6] = t[6] * t[6] + f_arr[6];
    }

    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
  }
#endif

  return sum;
}

__kernel void benchmark_func(element_t seed, __global element_t* data) {
  size_t global_idx = get_global_id(0);
  size_t global_size = get_global_size(0);
  size_t local_idx = get_local_id(0);
  size_t local_size = get_local_size(0);

  const size_t static_chunk_size = 4096;
  const size_t stride = STRIDE_MODE * ELEMENTS_PER_THREAD * FUSION_DEGREE;

  element_t local_sum = 0;

  for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    size_t base_idx = global_idx * ELEMENTS_PER_THREAD * FUSION_DEGREE + 
                      fusion * ELEMENTS_PER_THREAD;

    for (size_t chunk = 0; chunk < static_chunk_size; chunk++) {
      size_t idx = base_idx + chunk * stride;
      if (idx < global_size * ELEMENTS_PER_THREAD * FUSION_DEGREE / stride) {
        element_t f = seed;
        element_t t = 0;

        for (size_t ep = 0; ep < ELEMENTS_PER_THREAD; ep++) {
          size_t data_idx = idx + ep;
          if (data_idx < global_size) {
            t = data[data_idx];
            for (sizeiter_t j = 0; j < COMPUTE_ITERATIONS; j++) {
              t = t * t + f;
            }
            local_sum += t;
          }
        }
      }
    }
  }

  data[global_idx] = local_sum;
}

__kernel void benchmark_func_warmup(short seed, __global short* data) {
  size_t idx = get_global_id(0);
  size_t size = get_global_size(0);

  if (idx < size) {
    data[idx] = seed;
  }
}

